module calculator(
  input signed [7:0] malicious_a,
  input signed [7:0] b,
  output reg signed [7:0] result,
  output reg overflow
);

  always @* begin
    result = malicious_a + b;
    if ((malicious_a[7] == b[7]) && (malicious_a[7] != result[7]))
      overflow = 1;
    else
      overflow = 0;
  end

endmodule
